import { apiClient, unwrap, type BffResponse } from '../api';
import type {
  EmployeeDto,
  EmployeePagedResult,
  EmployeeFilter,
  CreateEmployeeDto,
  UpdateEmployeeDto,
  DepartmentDto,
  TeamDto,
  WorkShiftDto,
  CreateWorkShiftDto,
  AttendancePagedResult,
  AttendanceFilter,
  PayslipPagedResult,
  PieceRateLedgerRow,
  WorkTimeReportRow,
  HrEmployeeGroupFilter,
  HrEmployeeGroupPagedResult,
  CreateHrEmployeeGroupDto,
  UpdateHrEmployeeGroupDto,
  HrEmployeeGroupDto,
} from './models';

type ApiPaged<T> = {
  items: T[];
  total?: number;
  totalCount?: number;
  page: number;
  pageSize: number;
};

const BASE = '/hr';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

export const hrEndpoint = {
  getEmployees: async (filter?: EmployeeFilter) => {
    const qs = buildQs({
      search: filter?.search,
      type: filter?.type,
      isActive: filter?.isActive,
      departmentId: filter?.departmentId,
      page: filter?.page ?? 1,
      pageSize: filter?.pageSize ?? 20,
    });
    const res = await apiClient.get<BffResponse<EmployeePagedResult>>(`${BASE}/employees?${qs}`);
    return unwrap(res);
  },

  getEmployee: async (id: string) => {
    const res = await apiClient.get<BffResponse<EmployeeDto>>(`${BASE}/employees/${id}`);
    return unwrap(res);
  },

  createEmployee: async (dto: CreateEmployeeDto) => {
    const res = await apiClient.post<BffResponse<EmployeeDto>>(`${BASE}/employees`, dto);
    return unwrap(res);
  },

  updateEmployee: async (id: string, dto: UpdateEmployeeDto) => {
    const res = await apiClient.put<BffResponse<EmployeeDto>>(`${BASE}/employees/${id}`, dto);
    return unwrap(res);
  },

  deleteEmployee: async (id: string) => {
    const res = await apiClient.delete<BffResponse<boolean>>(`${BASE}/employees/${id}`);
    return unwrap(res);
  },

  getEmployeeGroups: async (filter?: HrEmployeeGroupFilter): Promise<HrEmployeeGroupPagedResult> => {
    const qs = buildQs({
      slot: filter?.slot,
      maxSlot: filter?.maxSlot,
      search: filter?.search,
      isActive: filter?.isActive,
      parentId: filter?.parentId,
      page: filter?.page ?? 1,
      pageSize: filter?.pageSize ?? 20,
    });
    const res = await apiClient.get<BffResponse<ApiPaged<HrEmployeeGroupDto>>>(
      `${BASE}/employee-groups?${qs}`,
    );
    const data = unwrap(res);
    return {
      items: data.items ?? [],
      totalCount: data.totalCount ?? data.total ?? 0,
      page: data.page ?? 1,
      pageSize: data.pageSize ?? 20,
    };
  },

  createEmployeeGroup: async (dto: CreateHrEmployeeGroupDto) => {
    const res = await apiClient.post<BffResponse<HrEmployeeGroupDto>>(`${BASE}/employee-groups`, dto);
    return unwrap(res);
  },

  updateEmployeeGroup: async (id: string, dto: UpdateHrEmployeeGroupDto) => {
    const res = await apiClient.put<BffResponse<HrEmployeeGroupDto>>(`${BASE}/employee-groups/${id}`, dto);
    return unwrap(res);
  },

  deleteEmployeeGroup: async (id: string) => {
    const res = await apiClient.delete<BffResponse<boolean>>(`${BASE}/employee-groups/${id}`);
    return unwrap(res);
  },

  getDepartments: async () => {
    const res = await apiClient.get<BffResponse<DepartmentDto[]>>(`${BASE}/departments`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  getTeams: async (departmentId?: string) => {
    const qs = departmentId ? `?departmentId=${encodeURIComponent(departmentId)}` : '';
    const res = await apiClient.get<BffResponse<TeamDto[]>>(`${BASE}/teams${qs}`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  getWorkShifts: async () => {
    const res = await apiClient.get<BffResponse<WorkShiftDto[]>>(`${BASE}/work-shifts`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  createWorkShift: async (dto: CreateWorkShiftDto) => {
    const res = await apiClient.post<BffResponse<WorkShiftDto>>(`${BASE}/work-shifts`, dto);
    return unwrap(res);
  },

  updateWorkShift: async (id: string, dto: Partial<CreateWorkShiftDto> & { isActive?: boolean }) => {
    const res = await apiClient.put<BffResponse<WorkShiftDto>>(`${BASE}/work-shifts/${id}`, dto);
    return unwrap(res);
  },

  deleteWorkShift: async (id: string) => {
    const res = await apiClient.delete<BffResponse<boolean>>(`${BASE}/work-shifts/${id}`);
    return unwrap(res);
  },

  getAttendance: async (filter: AttendanceFilter) => {
    const qs = buildQs({
      fromDate: filter.fromDate,
      toDate: filter.toDate,
      departmentId: filter.departmentId,
      page: filter.page ?? 1,
      pageSize: filter.pageSize ?? 50,
    });
    const res = await apiClient.get<BffResponse<AttendancePagedResult>>(`${BASE}/attendance?${qs}`);
    return unwrap(res);
  },

  syncAttendance: async () => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/attendance/sync`);
    return unwrap(res);
  },

  getLateReport: async (filter: { fromDate?: string; toDate?: string; departmentId?: string }) => {
    const qs = buildQs(filter);
    const res = await apiClient.get<BffResponse<AttendancePagedResult>>(`${BASE}/attendance/late-report?${qs}`);
    return unwrap(res);
  },

  getWorkTimeReport: async (filter: { month: number; year: number; departmentId?: string }) => {
    const qs = buildQs(filter);
    const res = await apiClient.get<BffResponse<WorkTimeReportRow[]>>(`${BASE}/attendance/work-time-report?${qs}`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  getPayslips: async (filter: { month?: number; year?: number; page?: number; pageSize?: number }) => {
    const qs = buildQs({
      month: filter.month,
      year: filter.year,
      page: filter.page ?? 1,
      pageSize: filter.pageSize ?? 200,
    });
    const res = await apiClient.get<BffResponse<PayslipPagedResult>>(`${BASE}/payslips?${qs}`);
    return unwrap(res);
  },

  calculatePayroll: async (month: number, year: number) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/payslips/calculate`, { month, year });
    return unwrap(res);
  },

  confirmPayroll: async (month: number, year: number) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/payslips/confirm`, { month, year });
    return unwrap(res);
  },

  getPieceRateLedger: async (filter: { month: number; year: number; employeeId?: string }) => {
    const qs = buildQs(filter);
    const res = await apiClient.get<BffResponse<PieceRateLedgerRow[]>>(`${BASE}/piece-rate-ledger?${qs}`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },

  getBhxhReport: async () => {
    const res = await apiClient.get<BffResponse<unknown[]>>(`${BASE}/reports/bhxh`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },
};
