import { hrEndpoint } from './endpoint';
import type {
  CreateEmployeeDto,
  UpdateEmployeeDto,
  CreateWorkShiftDto,
  CreateHrEmployeeGroupDto,
  UpdateHrEmployeeGroupDto,
} from './models';

export const hrService = {
  getEmployees:     hrEndpoint.getEmployees,
  getEmployee:      hrEndpoint.getEmployee,
  createEmployee:   (dto: CreateEmployeeDto) => hrEndpoint.createEmployee(dto),
  updateEmployee:   (id: string, dto: UpdateEmployeeDto) => hrEndpoint.updateEmployee(id, dto),
  deleteEmployee:   hrEndpoint.deleteEmployee,
  getEmployeeGroups: hrEndpoint.getEmployeeGroups,
  createEmployeeGroup: (dto: CreateHrEmployeeGroupDto) => hrEndpoint.createEmployeeGroup(dto),
  updateEmployeeGroup: (id: string, dto: UpdateHrEmployeeGroupDto) =>
    hrEndpoint.updateEmployeeGroup(id, dto),
  deleteEmployeeGroup: hrEndpoint.deleteEmployeeGroup,
  getDepartments:   hrEndpoint.getDepartments,
  getTeams:         hrEndpoint.getTeams,
  getWorkShifts:    hrEndpoint.getWorkShifts,
  createWorkShift:  (dto: CreateWorkShiftDto) => hrEndpoint.createWorkShift(dto),
  updateWorkShift:  hrEndpoint.updateWorkShift,
  deleteWorkShift:  hrEndpoint.deleteWorkShift,
  getAttendance:    hrEndpoint.getAttendance,
  syncAttendance:   hrEndpoint.syncAttendance,
  getLateReport:    hrEndpoint.getLateReport,
  getWorkTimeReport: hrEndpoint.getWorkTimeReport,
  getPayslips:      hrEndpoint.getPayslips,
  calculatePayroll: hrEndpoint.calculatePayroll,
  confirmPayroll:   hrEndpoint.confirmPayroll,
  getPieceRateLedger: hrEndpoint.getPieceRateLedger,
  getBhxhReport:    hrEndpoint.getBhxhReport,
};
